func:
// Parameters:
// msg.payload.artist - artist name
// msg.payload.style - song style
// msg.payload.lyrics - base lyrics
// Input example:
// { artist: 'Adele', style: 'ballad', lyrics: 'Hello from the other side' }
// Output example:
// msg.prompt = 'Create a ballad style song for Adele. Lyrics: Hello from the other side'
const { artist, style, lyrics } = msg.payload;
msg.prompt = `Create a ${style} style song for ${artist}. Lyrics: ${lyrics}`;
return msg;

// Input: msg.prompt
// Output example:
// msg.suno = { audioUrl: 'https://suno.ai/audio/123.mp3' }
const axios = require('axios');
return axios.post('https://api.suno.ai/generate', { prompt: msg.prompt })
  .then(res => { msg.suno = res.data; return msg; });

// Input: msg.suno.audioUrl
// Output example:
// msg.drive = { fileId: '1A2B3C' }
const { google } = require('googleapis');
const axios = require('axios');
const drive = google.drive({ version: 'v3' });
// OAuth setup omitted for brevity
return axios({ url: msg.suno.audioUrl, method: 'GET', responseType: 'stream' })
  .then(response => drive.files.create({ requestBody: { name: 'suno.mp3' }, media: { mimeType: 'audio/mpeg', body: response.data } }))
  .then(res => { msg.drive = { fileId: res.data.id }; return msg; });

// Input: msg.drive.fileId
// Output: msg
const axios = require('axios');
return axios.post('https://api.raycast.com/notify', { fileId: msg.drive.fileId })
  .then(() => msg);
